fun greet(name: String?): String {
    val safe = name ?: "stranger"
    return "Hello, $safe!"
}

fun main() {
    println(greet("Alice"))
    println(greet(null))
}

class Person(val name: String, var age: Int) {
    fun greet() = "Hi, I'm $name and I'm $age."
}

fun main() {
    val p = Person("Alice", 30)
    println(p.greet())
    p.age = 31
    println(p.age)
}

fun main() {
    val nums = listOf(1, 2, 3, 4, 5)
    val evens = nums.filter { it % 2 == 0 }
    val doubled = evens.map { it * 2 }
    println(doubled)
}

fun applyTwice(x: Int, f: (Int) -> Int): Int = f(f(x))

fun main() {
    val result = applyTwice(3) { it * 2 }
    println(result)
}

